(24, 1, 'Madai Kristóf', 'Kata ügyfelei akik Kittihez kerültek át: Ficze László, Lakatosnè Emese, Ruha Melinda, Rèzműves Ferenc, Szerencsi László, Erősnè Balogh Èva, Csizmadiánè Almási Zsuzsa', '2025-12-02 08:28:54'),
(25, 11, 'Balogh Tibor', 'a megjegyzésben maradjon már Kata, mert az alapján számolok el vele, mert Ő hozta az ügyfeleket.', '2025-12-02 08:52:23'),
(26, 1, 'Madai Kristóf', 'Oda írom, mert szerintem amikor töröltem a rendszerből, akkor törlődtek azok is.', '2025-12-02 08:54:13'),
(27, 1, 'Madai Kristóf', 'Javítottam a hibát Anett. Mostmár nyugodtan bepipálhatod a szerződést ha új ügyfelet adsz hozzá.', '2025-12-03 14:07:18'),
(28, 10, 'Balogh Anett', 'Oké', '2025-12-03 19:54:55'),
(29, 10, 'Balogh Anett', 'Szia Kristóf tegnap 11 et csináltam és azok hova tűntek', '2025-12-04 07:23:29'),
(30, 10, 'Balogh Anett', 'Mert csak 8 db ot látok', '2025-12-04 07:25:19'),
(31, 10, 'Balogh Anett', 'Van a pasztor László ő kékcsei öt bejeloltem de ő sincs ott', '2025-12-04 07:30:28'),
(32, 10, 'Balogh Anett', 'Van a dobrai László ő Ankara való Dobrai Ferencné névre csináltam', '2025-12-04 07:32:27'),
(33, 10, 'Balogh Anett', 'És van a Kovács József ő pedig tornyospálci', '2025-12-04 07:33:02'),
(34, 10, 'Balogh Anett', 'Szerkesztésbe nem tudom a nevet megvaltoztatni', '2025-12-04 07:33:46'),
(35, 1, 'Madai Kristóf', 'Nézem egy pillanat', '2025-12-04 08:09:40'),
