INSERT INTO `patchnotes` (`id`, `version`, `title`, `content`, `created_by`, `created_at`, `is_major`) VALUES
(3, '1.0', 'Mobil, és keresés.', '-Több ügyfél kijelölése, illetve szerkesztése működik.\r\n-Fejlesztési napló bekerült.( Csak azért, hogy ne lepődjetek meg ha bármi változik)\r\n-Üzenetek funkció. ( Itt tud minden admin, illetve ügyintéző beszélni, hogy ne kelljen felhívni a másikat vagy bármi ha valami kérdés vagy probléma van.\r\n-Mobilbarátabbá tettem a rendszert.', 'Madai Kristóf', '2025-11-27 10:26:45', 1),
(4, '1.1', 'Változások új.', '-Mostantól amennyiben egy megyéhez új ügyfelet rögzítettek, azt fogja a rendszer jelezni a megye választóban.\r\n-Az új üzeneteket egy kis ablakban fogja a rendszer szintén jelölni, illetve az ikonnál. (Így ha fontos az üzenet egybőll fogjátok látni)\r\n-Adminoknak külön jelzi a rendszer, ha függőben lévő jóváhagyásuk van.', 'Madai Kristóf', '2025-11-28 10:06:35', 1),
(6, '1.2', 'Új ügyfél jóváhagyások.', '-Mostantól mindenki látni fogja egy külön fülön (az oldal tetején \"Saját kérések\") a függőben lévő ügyfélkéréseit (Amennyiben új ügyfelet szeretnétek hozzá adni a rendszerhez, az \"Új ügyfél\" oldalon). \r\n-3 lap lesz ott. \"Függőben\", \"Elfogadva\", \"Elutasítva\". \r\n-Külön értesítést kaptok amennyiben egy admin elutasítja, vagy elfogadja a kéréseteket. \r\n-Amennyiben elutasításra kerül a kérés, látni fogjátok az indokot hogy miért.\r\n-Elutasítást követően nem kell újra beírni az ügyfél adatait, csak annyit kell tenni, hogy bementek a \"Saját kérések\" fülre, ott az \"Elutasítva\" oldal, és ott lesz lehetőség \"Újraküldeni\" a javított változatot.', 'Madai Kristóf', '2025-12-01 08:19:42', 1),
(7, '1.2.1', 'Hibajavítás', 'Javítottam azt a hibát ha egy ügyintéző új ügyfél hozzáadásánál bepipálja a szerződéskötést, akkor nem veszi a rendszer figyelembe a statisztika oldalon.', 'Madai Kristóf', '2025-12-03 14:06:35', 1);
